<style>
    .absolute {
        position: absolute;
    }

    .top-0 {
        top: 0px;
    }

    .mx-auto {
        margin-left: auto;
        margin-right: auto;
    }

    .flex {
        display: flex;
    }

    .hidden {
        display: none;
    }

    .min-h-screen {
        min-height: 100vh;
    }

    .w-1\/12 {
        width: 8.333333%;
    }

    .w-full {
        width: 100%;
    }

    .w-1\/4 {
        width: 25%;
    }

    .items-center {
        align-items: center;
    }

    .justify-center {
        justify-content: center;
    }

    .bg-black {
        --tw-bg-opacity: 1;
        background-color: rgb(0 0 0 / var(--tw-bg-opacity));
    }

    .bg-transparent {
        background-color: transparent;
    }

    .bg-white {
        --tw-bg-opacity: 1;
        background-color: rgb(255 255 255 / var(--tw-bg-opacity));
    }

    .fill-transparent {
        fill: transparent;
    }

    .transition-colors {
        transition-property: color, background-color, border-color, text-decoration-color, fill, stroke;
        transition-timing-function: cubic-bezier(0.4, 0, 0.2, 1);
        transition-duration: 150ms;
    }
</style>

